plugin.detectCode:
// Matches ChatABA output URLs: http://<ip>:<port>/temp/commands/<job_id>/...
const t = input.trim();
return /^https?:\/\/[\d.]+:\d+\/temp\/commands\/[a-f0-9]+\b/i.test(t) ? 0.98 : 0;

plugin.executeCode:
try {
  const t = input.trim();
  const url = new URL(t);
  const match = url.pathname.match(/^\/temp\/commands\/([^/]+)/);
  if (!match) {
    return { output: '', error: 'Could not extract job_id. Expected: /temp/commands/<job_id>/...' };
  }
  const ip = url.hostname;
  const port = url.port || '(default)';
  const jobId = match[1];
  const uncPath = '\\\\' + ip + '\\Soil_Share\\commands\\' + jobId;
  const lines = [
    'URL:           ' + t,
    '',
    'Host IP:       ' + ip,
    'Port:          ' + port,
    'Job ID:        ' + jobId,
    'Full Path:     ' + url.pathname,
    '',
    'UNC Share Path:',
    '  ' + uncPath,
  ];
  return { output: lines.join('\n'), outputLanguage: 'text' };
} catch (err) {
  return { output: '', error: err instanceof Error ? err.message : 'Failed to parse ChatABA URL' };
}
